import{_ as a,o,c as t,a0 as r}from"./chunks/framework.jwovEGr5.js";const s="/images/backup-restore/Pasted%20image%2020260704171338.png",p="/images/backup-restore/Pasted%20image%2020260704171520.png",c="/images/backup-restore/Pasted%20image%2020260704171806.png",i="/images/backup-restore/Pasted%20image%2020260704172007.png",d="/images/backup-restore/Pasted%20image%2020260704172433.png",m="/images/backup-restore/Pasted%20image%2020260704172557.png",n="/images/backup-restore/Pasted%20image%2020260704172643.png",l="/images/backup-restore/Pasted%20image%2020260704172904.png",g="/images/backup-restore/Pasted%20image%2020260704173035.png",h="/images/backup-restore/Pasted%20image%2020260704173201.png",_="/images/backup-restore/Pasted%20image%2020260704173132.png",R=JSON.parse('{"title":"备份与恢复","description":"","frontmatter":{},"headers":[],"relativePath":"backup-restore.md","filePath":"backup-restore.md"}'),u={name:"backup-restore.md"};function b(k,e,P,f,q,x){return o(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="备份与恢复" tabindex="-1">备份与恢复 <a class="header-anchor" href="#备份与恢复" aria-label="Permalink to &quot;备份与恢复&quot;">​</a></h1><h2 id="引言" tabindex="-1">引言 <a class="header-anchor" href="#引言" aria-label="Permalink to &quot;引言&quot;">​</a></h2><p>做任何事都不要头脑一热，不计后果的做，学习通里有重要的<strong>聊天记录</strong>，如果你安装<a href="https://github.com/qcxs/chaoxing#%E8%B5%84%E6%96%99" target="_blank" rel="noreferrer">资料</a>中的修改版，系统会提示你<em>与已安装的应用签名不一致，需要你卸载已安装的版本</em>，再继续安装。如果你冒然卸载，就会丢失聊天记录，但其实这是可以避免的。</p><h2 id="教程" tabindex="-1">教程 <a class="header-anchor" href="#教程" aria-label="Permalink to &quot;教程&quot;">​</a></h2><h3 id="备份" tabindex="-1">备份 <a class="header-anchor" href="#备份" aria-label="Permalink to &quot;备份&quot;">​</a></h3><p>新版本为了便于向鸿蒙迁移，提供了备份功能，如果不是新版本，请更新版本</p><p><img src="'+s+'" alt=""></p><p>先点击<code>计算文件大小</code>，再点击<code>开始备份</code></p><p><img src="'+p+'" alt=""></p><p>去 MT 定位文件 <code>/storage/emulated/0/Download/chaoxing/com.chaoxing.mobile.zip</code>，这就是你的聊天记录备份文件。然后就可以卸载重装了，重装后登录自己的账号，发现丢失聊天记录。</p><h3 id="恢复" tabindex="-1">恢复 <a class="header-anchor" href="#恢复" aria-label="Permalink to &quot;恢复&quot;">​</a></h3><h4 id="有-root" tabindex="-1">有 Root <a class="header-anchor" href="#有-root" aria-label="Permalink to &quot;有 Root&quot;">​</a></h4><p>打开备份压缩包，将文件夹 <code>com.chaoxing.mobile/ce/</code> 里面的内容解压至 <code>/data/user/0/com.chaoxing.mobile/</code></p><p><img src="'+c+'" alt=""></p><p>全部覆盖</p><p><img src="'+i+'" alt=""></p><p>关闭 app，重新打开，即可发现数据成功恢复。</p><h4 id="没有-root" tabindex="-1">没有 Root <a class="header-anchor" href="#没有-root" aria-label="Permalink to &quot;没有 Root&quot;">​</a></h4><p>找到资料中的安装包，选择<code>功能</code>，<code>注入文件提供器</code>，最新版资料我已注入，可跳过此步骤</p><p><img src="'+d+'" alt=""></p><p>MT 侧边栏，选择<code>添加本地存储</code></p><p><img src="'+m+'" alt=""></p><p>点击<code>学习通</code></p><p><img src="'+n+'" alt=""></p><p><code>使用此文件夹</code>，<code>允许</code></p><p><img src="'+l+'" alt=""></p><p>接下来就可以在 MT 侧栏找到学习通了</p><p><img src="'+g+'" alt=""></p><p>进入 <code>data</code> 文件夹</p><p><img src="'+h+'" alt=""></p><p>也是一样，直接复制替换即可</p><p><img src="'+_+'" alt=""></p><h2 id="注" tabindex="-1">注 <a class="header-anchor" href="#注" aria-label="Permalink to &quot;注&quot;">​</a></h2><p>推荐同包名、同版本、同账号的<em>学习通备份文件</em>恢复，否则出现问题后果自负。</p>',34)])])}const S=a(u,[["render",b]]);export{R as __pageData,S as default};
